function installAllDecks() {
  if (!window.data) return 0;
  if (!Array.isArray(window.data.dictionary)) window.data.dictionary = [];
  if (window.data.allDecksLoaded) return 0;
  const today = (typeof todayStr === 'function') ? todayStr() : new Date().toISOString().slice(0,10);
  let added = 0;
  for (const d of extraDefaultDefinitions) {
    const exists = window.data.dictionary.some(w =>
      (w.jp && d.jp && w.jp === d.jp && (!d.es || w.es === d.es)) ||
      (w.es && d.es && w.es === d.es && (!d.jp || w.jp === d.jp)) ||
      (w.en && d.en && !d.jp && !d.es && w.en.toLowerCase() === d.en.toLowerCase())
    );
    if (exists) continue;
    window.data.dictionary.push({
      en: d.en, jp: d.jp, es: d.es,
      tags: (d.tags || []).slice(),
      type: d.type || 'other',
      addedDate: today,
      uses: 0, correct: 0,
    });
    added++;
  }
  window.data.allDecksLoaded = true;
  if (typeof saveData === 'function') saveData();
  if (typeof renderDictionary === 'function') renderDictionary();
  if (typeof updateStats === 'function') updateStats();
  console.log('[default-deck-extra] installed', added, 'entries');
  return added;
}

function tryInstallAllDecks() {
  if (typeof data === 'undefined' || !window.data) { setTimeout(tryInstallAllDecks, 200); return; }
  // Wait for the original Sakuuta default deck to land first so the flags
  // don't race.
  if (!window.data.defaultDeckLoaded) { setTimeout(tryInstallAllDecks, 200); return; }
  installAllDecks();
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => setTimeout(tryInstallAllDecks, 120));
} else {
  setTimeout(tryInstallAllDecks, 120);
}
